$repo = "denolehov/obsidian-git"
$release = Invoke-RestMethod -Uri "https://api.github.com/repos/$repo/releases/latest"
$pluginDir = "D:\iCloudDrive\.obsidian\IRP Management\.obsidian\plugins\obsidian-git"
New-Item -ItemType Directory -Force -Path $pluginDir
foreach ($asset in $release.assets) {
    Invoke-WebRequest -Uri $asset.browser_download_url -OutFile "$pluginDir\$($asset.name)"
}
$jsonPath = "D:\iCloudDrive\.obsidian\IRP Management\.obsidian\community-plugins.json"
$json = Get-Content $jsonPath | ConvertFrom-Json
if ("obsidian-git" -notin $json) {
    $json += "obsidian-git"
    $json | ConvertTo-Json | Set-Content $jsonPath
}
